import { useState, useEffect, useRef, useCallback } from 'react';

export const useProgressQueue = (duration = 3000) => {
    const [queue, setQueue] = useState([]);

    // Refs for animation "engine" state to avoid closure staleness
    const requestRef = useRef();
    const startTimeRef = useRef(null);
    const activeIndexRef = useRef(0);
    const isAnimatingRef = useRef(false);

    const animate = useCallback((time) => {
        if (startTimeRef.current === null) {
            startTimeRef.current = time;
        }

        const elapsed = time - startTimeRef.current;
        const progress = Math.min((elapsed / duration) * 100, 100);

        // Update the state for the specific bar
        setQueue((prev) => {
            const newQueue = [...prev];
            newQueue[activeIndexRef.current] = progress;
            return newQueue;
        });

        if (progress < 100) {
            requestRef.current = requestAnimationFrame(animate);
        } else {
            // Bar finished: Reset for the next one
            startTimeRef.current = null;
            activeIndexRef.current += 1;
            isAnimatingRef.current = false;

            // Check if there are more bars waiting in the queue
            // We check the 'queue' length via a ref-like check or 
            // by simply letting the next useEffect cycle catch it.
        }
    }, [duration]);

    const addBar = useCallback(() => {
        setQueue((prev) => [...prev, 0]);
    }, []);

    useEffect(() => {
        // If we have bars to process and we aren't currently animating
        if (activeIndexRef.current < queue.length && !isAnimatingRef.current) {
            isAnimatingRef.current = true;
            requestRef.current = requestAnimationFrame(animate);
        }

        return () => cancelAnimationFrame(requestRef.current);
    }, [queue.length, animate]); // Trigger whenever the list grows

    return { queue, addBar };
};
